import type { BaseSliderProps } from '../base/Slider.base.types';
export interface MultiSliderProps extends Omit<BaseSliderProps, 'value' | 'onChange'> {
    /**
     * Начальное значение для ползунка слайдера в виде массива [значение левого ползунка, значение правого ползунка]
     */
    value: [startValue: number, endValue: number];
    /**
     * Событие изменения положения ползунка, возвращает значение в виде массива [значение левого ползунка, значение правого ползунка]
     */
    onChange?: (value: MultiSliderProps['value']) => void;
}
